def debug_logger(prefix=""):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            print(f"{prefix} Calling {func.__name__}")
            result = func(*args, **kwargs)
            print(f"{prefix} {func.__name__} returned {result}")
